function renderNodeChoices(container,nodes,allowedIds,inputClass="node-choice"){
  const selected=new Set(allowedIds||[]);
  container.innerHTML=(nodes||[]).map(node=>`<label><input class="${inputClass}" type="checkbox" value="${escapeHtml(node.id)}" ${selected.has(node.id)?"checked":""}><span>${escapeHtml(node.name||node.id)}</span></label>`).join("")||'<span class="notice">暂无可用节点</span>';
}
function wireAllNodeToggle(toggle,container){const sync=()=>container.querySelectorAll('input[type="checkbox"]').forEach(input=>input.disabled=toggle.checked);toggle.onchange=sync;sync()}
function selectedNodeIds(toggle,container){return toggle.checked?[]:[...container.querySelectorAll('input[type="checkbox"]:checked')].map(input=>input.value)}
function dateTimeLocalValue(value){if(!value)return"";const date=new Date(value),offset=date.getTimezoneOffset()*60000;return new Date(date.getTime()-offset).toISOString().slice(0,16)}
async function ensureSubscriptionNodes(){if(adminSubscriptionNodes.length)return;const data=await api("/api/admin/subscriptions");adminSubscriptionNodes=data.nodes||[]}
