async function loadCustomerSubscriptions(){
  const status=$("#customer-subscription-status");
  try{
    const data=await api("/api/customer/subscriptions");if(session?.role!=="customer")return;const account=data.account||{},plans=data.plans||[],orders=data.orders||[],nodes=data.nodes||[],paymentConfigured=!!data.paymentConfigured,pending=orders.filter(order=>["pending","pending_payment","paid"].includes(order.status)),summary=$$("#customer-subscription-summary>div");
    summary[0].querySelector("strong").textContent=account.activeSubscriptionName||"基础权益";
    summary[1].querySelector("strong").textContent=account.subscriptionExpiresAt?new Date(account.subscriptionExpiresAt).toLocaleDateString():"长期有效";
    summary[1].querySelector("strong").classList.toggle("subscription-expired",!!account.subscriptionExpired);
    summary[2].querySelector("strong").textContent=String(pending.length);
    const pendingPlanIds=new Set(pending.map(order=>order.planId));
    $("#customer-subscription-plans").innerHTML=plans.map(plan=>{const waiting=pendingPlanIds.has(plan.id),paymentUnavailable=Number(plan.priceCents)>0&&!paymentConfigured,disabled=waiting||paymentUnavailable,label=waiting?"已有未完成订单":paymentUnavailable?"支付暂不可用":Number(plan.priceCents)>0?"购买套餐":"提交申请";return`<article class="subscription-card" data-kind="${escapeHtml(plan.kind)}"><div class="subscription-card-head"><span class="tag">${subscriptionKindName(plan.kind)}</span><small>${subscriptionDurationText(plan.kind)}</small></div><h2>${escapeHtml(plan.name)}</h2><strong class="subscription-price">${fmtPrice(plan.priceCents,plan.currency)}</strong><div class="subscription-allowance"><span>包含流量</span><b>${fmtBytes(plan.trafficBytes)}</b></div><dl class="plan-benefits"><div><dt>服务节点</dt><dd>${escapeHtml(nodeEntitlementText(plan.allowedNodeIds,nodes))}</dd></div><div><dt>通道上限</dt><dd>${plan.maxChannels?`${plan.maxChannels} 个`:"不限"}</dd></div><div><dt>批准方式</dt><dd>${plan.autoApprove?"自动批准":"人工审核"}</dd></div></dl><button class="${disabled?"":"primary"} subscription-request" data-plan-id="${escapeHtml(plan.id)}" type="button" ${disabled?"disabled":""}>${label}</button></article>`}).join("")||'<div class="subscription-empty">管理员尚未发布可订阅套餐。</div>';
    $("#customer-subscription-orders-body").innerHTML=orders.map(order=>{const[state,stateClass]=subscriptionStatus(order.status),pay=order.status==="pending_payment"?(paymentConfigured?`<button class="primary subscription-pay" data-order-id="${escapeHtml(order.id)}" type="button">去支付</button>`:'<span class="tag off">支付暂不可用</span>'):escapeHtml(order.reviewNote||"—");return`<tr><td><strong>${escapeHtml(order.planName)}</strong></td><td>${subscriptionKindName(order.kind)}</td><td>${fmtBytes(order.trafficBytes)}</td><td>${fmtPrice(order.priceCents,order.currency)}</td><td>${new Date(order.createdAt).toLocaleString()}</td><td><span class="tag ${stateClass}">${state}</span></td><td>${pay}</td></tr>`}).join("")||emptyRow(7,"暂无订阅申请");
    $$(".subscription-request").forEach(button=>button.onclick=()=>requestSubscription(button,plans.find(plan=>plan.id===button.dataset.planId)));
    $$(".subscription-pay").forEach(button=>button.onclick=()=>window.location.assign(`/api/customer/subscriptions/orders/${encodeURIComponent(button.dataset.orderId)}/pay`));
    status.textContent=account.subscriptionExpired?"当前时长权益已到期，续订生效后桌面连接将恢复。":`当前可用节点：${nodeEntitlementText(account.allowedNodeIds,nodes)}；通道上限：${account.maxChannels||"不限"}。`;
    decorateResponsiveTables();
  }catch(error){if(session?.role!=="customer")return;status.textContent=error.message;toast(error.message)}
}
