async function repairFrps(statusElement){try{if(statusElement)statusElement.textContent="正在自动修复 frps，请稍候...";const r=await api("/api/frps/repair",{method:"POST"});if(statusElement)statusElement.textContent=r.message;toast(r.message);await refresh();if(!$("#page-maintenance").classList.contains("hidden"))await detectFrps();return r}catch(e){if(statusElement)statusElement.textContent=e.message;toast(e.message);throw e}}
$("#repair-frps").onclick=()=>repairFrps(null).catch(()=>{});
$("#install-frps").onclick=async()=>{const status=$("#install-status");try{await repairFrps(status);loadNodes()}catch{}};
$("#detect-frps").onclick=()=>detectFrps().catch(e=>toast(e.message));
$("#maintenance-install-frps").onclick=async()=>{const status=$("#maintenance-frps-status");try{await repairFrps(status);await detectFrps()}catch{}};
$("#check-server-update").onclick=()=>checkUpdate().catch(e=>toast(e.message));
$("#apply-server-update").onclick=async()=>{const status=$("#maintenance-update-status");try{status.textContent="正在下载更新，完成后服务会自动重启...";const r=await api("/api/update",{method:"POST"});status.textContent=r.message;toast(r.message)}catch(e){status.textContent=e.message;toast(e.message)}};
$("#advanced-config").onclick=async()=>{advanced=!advanced;$("#config-form").classList.toggle("hidden",advanced);$("#config-editor").classList.toggle("hidden",!advanced);$("#advanced-config").textContent=advanced?"返回模块化配置":"高级文本编辑";if(advanced){const r=await api("/api/config");$("#config-editor").value=r.content||""}};
$("#save-config").onclick=async()=>{const status=$("#config-status");status.textContent="正在校验...";try{const r=advanced?await api("/api/config",{method:"PUT",body:JSON.stringify({content:$("#config-editor").value,restart:true})}):await api("/api/config/model",{method:"PUT",body:JSON.stringify(configPayload())});status.textContent=r.message;toast(r.message)}catch(e){status.textContent=e.message;toast(e.message)}};
