$("#version-button").onclick=async()=>{if($("#version-button").dataset.available!=="true"){checkUpdate();return}try{const r=await api("/api/update",{method:"POST"});toast(r.message)}catch(e){toast(e.message)}};
(async()=>{try{session=await api("/api/session");if(session.authenticated&&["admin","customer"].includes(session.role)){showApp(session.role);refresh();checkUpdate()}else showLogin()}catch{showLogin()}})();
setInterval(()=>{if(session?.authenticated)refresh()},10000);
function decorateNodeNameInputs(){document.querySelectorAll(".node-name-edit").forEach(input=>{if(input.dataset.flagDecorated==="true")return;const info=splitLeadingFlag(input.value);if(!info.flag)return;input.value=info.name;input.dataset.leadingFlag=info.flag;input.dataset.flagDecorated="true";const wrap=document.createElement("span");wrap.className="node-name-cell";input.parentNode.insertBefore(wrap,input);const image=document.createElement("img");image.className="flag-icon";image.src=`/flags/${info.flag.toLowerCase()}.png`;image.alt=info.flag;wrap.append(image,input)})}
const originalLoadNodes=loadNodes;
loadNodes=async function(){await originalLoadNodes();decorateNodeNameInputs()};
document.addEventListener("click",event=>{const button=event.target.closest(".node-save");if(!button)return;const input=document.querySelector('.node-name-edit[data-id="'+button.dataset.id+'"]'),flag=nodeFlagEmoji[input?.dataset.leadingFlag];if(flag&&!input.value.startsWith(flag))input.value=flag+input.value},true);
function reloadAfterServerUpdate(){setTimeout(()=>{const deadline=Date.now()+60000;const probe=async()=>{try{const response=await fetch("/api/session",{cache:"no-store"});if(response.ok){window.location.reload();return}}catch{}if(Date.now()<deadline)setTimeout(probe,1500)};probe()},5000)}
async function applyServerUpdateFromPanel(){const status=$("#maintenance-update-status");try{status.textContent="正在下载更新，服务恢复后页面会自动刷新...";const result=await api("/api/update",{method:"POST"});status.textContent=result.message+" 正在等待服务恢复...";toast(result.message);reloadAfterServerUpdate()}catch(error){status.textContent=error.message;toast(error.message)}}
$("#apply-server-update").onclick=applyServerUpdateFromPanel;
$("#version-button").onclick=async()=>{if($("#version-button").dataset.available!=="true"){checkUpdate();return}await applyServerUpdateFromPanel()};
async function loadRegistrationSettings(){try{const settings=await api("/api/admin/registration-settings");$("#registration-enabled").checked=settings.enabled;$("#registration-quota").value=Math.round((settings.defaultTrafficQuotaBytes||0)/1024**3);$("#registration-status").textContent=settings.enabled?"注册已开放":"注册已关闭"}catch(error){$("#registration-status").textContent=error.message}}
async function loadSmtpSettings(){try{const s=await api("/api/admin/smtp-settings");$("#email-verification-enabled").checked=s.emailVerificationEnabled;$("#smtp-host").value=s.host||"";$("#smtp-port").value=s.port||587;$("#smtp-username").value=s.username||"";$("#smtp-password").value="";$("#smtp-password").placeholder=s.hasPassword?"已配置，留空保持不变":"请输入 SMTP 密码";$("#smtp-from-email").value=s.fromEmail||"";$("#smtp-from-name").value=s.fromName||"ZRfrp";$("#smtp-enable-ssl").checked=s.enableSsl;$("#smtp-verification-minutes").value=s.verificationMinutes||15;$("#smtp-subject").value=s.subjectTemplate||"";$("#smtp-html-template").value=s.htmlTemplate||"";$("#smtp-status").textContent=s.emailVerificationEnabled?"邮箱验证已开启":"邮箱验证已关闭"}catch(e){$("#smtp-status").textContent=e.message}}
async function loadTrafficStatus(){try{const s=await api("/api/admin/traffic-status");$("#traffic-collector-status").textContent=s.message}catch(e){$("#traffic-collector-status").textContent=e.message}}
async function loadSessionSettings(){try{const settings=await api("/api/admin/session-settings");$("#session-hours").value=settings.sessionHours;$("#session-status").textContent=`新登录授权有效 ${settings.sessionHours} 小时`}catch(error){$("#session-status").textContent=error.message}}
const baseLoadAccounts=loadAccounts;
loadAccounts=async function(){await baseLoadAccounts();await Promise.all([loadRegistrationSettings(),loadSessionSettings(),loadSmtpSettings(),loadTrafficStatus()])};
$("#show-register").onclick=async()=>{try{registrationSettings=await api("/api/auth/registration");if(!registrationSettings.enabled){$("#login-error").textContent="当前平台暂未开放账号注册。";return}const fields=$("#register-email-fields"),email=$("#register-email"),code=$("#register-code");if(fields)fields.classList.toggle("hidden",!registrationSettings.emailVerificationEnabled);if(email)email.required=registrationSettings.emailVerificationEnabled;if(code)code.required=registrationSettings.emailVerificationEnabled;$("#register-error").textContent="";showRegister()}catch(error){$("#login-error").textContent=error.message}};
