$("#register-form").onsubmit=async event=>{event.preventDefault();const error=$("#register-error"),username=$("#register-username").value.trim(),password=$("#register-password").value,confirm=$("#register-password-confirm").value,email=$("#register-email").value.trim(),verificationCode=$("#register-code").value.trim();error.textContent="";if(password!==confirm){error.textContent="两次输入的密码不一致。";return}try{const result=await api("/api/auth/register",{method:"POST",body:JSON.stringify({username,password,email,verificationCode})});$("#username").value=result.username||username;$("#password").value="";event.target.reset();showLogin();$("#login-error").textContent=result.message}catch(reason){error.textContent=reason.message}};
