$("#save-smtp-settings").onclick=async()=>{const status=$("#smtp-status"),payload={emailVerificationEnabled:$("#email-verification-enabled").checked,host:$("#smtp-host").value,port:Number($("#smtp-port").value),username:$("#smtp-username").value,password:$("#smtp-password").value,fromEmail:$("#smtp-from-email").value,fromName:$("#smtp-from-name").value,enableSsl:$("#smtp-enable-ssl").checked,verificationMinutes:Number($("#smtp-verification-minutes").value),subjectTemplate:$("#smtp-subject").value,htmlTemplate:$("#smtp-html-template").value};try{const r=await api("/api/admin/smtp-settings",{method:"PUT",body:JSON.stringify(payload)});status.textContent=r.message;toast(r.message);loadSmtpSettings()}catch(e){status.textContent=e.message;toast(e.message)}};
